ig = np.array(initial_grid)


def compute_score(gt, pred):
    pred = np.maximum(pred, FLOOR)
    pred = pred / pred.sum(axis=2, keepdims=True)
    total_entropy = 0
    weighted_kl = 0
    for y in range(40):
        for x in range(40):
            p = gt[y, x]
            q = pred[y, x]
            h = -np.sum(p * np.log(p + 1e-10))
            if h > 0.001:
                kl = np.sum(p * np.log((p + 1e-10) / (q + 1e-10)))
                weighted_kl += h * kl
                total_entropy += h
    wkl = weighted_kl / total_entropy if total_entropy > 0 else 0
    return 100 * np.exp(-3 * wkl), wkl


# 1. Upper bound: use GT as prediction
print("UPPER BOUND (GT = prediction):")
for s in range(5):
    gt = np.array(gt_data[f'seed_{s}'])
    score, wkl = compute_score(gt, gt.copy())
    print(f"  seed {s}: score={score:.2f} wKL={wkl:.6f}")

# 2. Global prior only
print("\nGLOBAL PRIOR ONLY:")
scores = []
for s in range(5):
    gt = np.array(gt_data[f'seed_{s}'])
    pred = np.zeros_like(gt)
    for y in range(40):
        for x in range(40):
            t = int(ig[y, x])
            pred[y, x] = EMPIRICAL.get(t, np.ones(6)/6)
    score, wkl = compute_score(gt, pred)
    scores.append(score)
    print(f"  seed {s}: score={score:.2f} wKL={wkl:.6f}")
print(f"  Average: {np.mean(scores):.2f}")

# 3. Simulate 1 observation per cell, various alpha
print("\nSIMULATED 1 OBS/CELL (mode as observation):")
for alpha in [0.1, 0.5, 1.0, 2.0]:
    scores = []
    for s in range(5):
        gt = np.array(gt_data[f'seed_{s}'])
        pred = np.zeros_like(gt)
        for y in range(40):
            for x in range(40):
                t = int(ig[y, x])
                if t == 10:
                    pred[y, x] = EMPIRICAL[10]
                else:
                    # 1 observation of the mode class
                    obs = np.zeros(6)
                    obs[gt[y, x].argmax()] = 1
                    prior = EMPIRICAL.get(t, np.ones(6) / 6)
                    K = 6
                    posterior = (obs + alpha) / (1 + K * alpha)
                    # Blend with empirical prior
                    w = 0.2
                    pred[y, x] = (1 - w) * posterior + w * prior
        score, wkl = compute_score(gt, pred)
        scores.append(score)
    print(f"  alpha={alpha}: avg={np.mean(scores):.2f} (range {min(scores):.2f}-{max(scores):.2f})")

# 4. What top teams likely do: use per-cell GT distribution
# With many sims, they approximate GT closely
# Key insight: with n observations, Dirichlet converges to truth
print("\nSIMULATED n OBS/CELL (sampling from GT distribution):")
np.random.seed(42)
for n_obs in [1, 2, 5, 10, 20]:
    scores = []
    for s in range(5):
        gt = np.array(gt_data[f'seed_{s}'])
        pred = np.zeros_like(gt)
        for y in range(40):
            for x in range(40):
                t = int(ig[y, x])
                if t == 10:
                    pred[y, x] = EMPIRICAL[10]
                else:
                    # Sample n observations from GT distribution
                    p_true = gt[y, x]
                    samples = np.random.choice(6, size=n_obs, p=p_true)
                    obs = np.zeros(6)
                    for c in samples:
                        obs[c] += 1
                    alpha = 0.5
                    K = 6
                    posterior = (obs + alpha) / (n_obs + K * alpha)
                    pred[y, x] = posterior
        score, wkl = compute_score(gt, pred)
        scores.append(score)
    print(f"  n={n_obs:2d}: avg={np.mean(scores):.2f} (range {min(scores):.2f}-{max(scores):.2f})")


